const allItems = $input.all();

// Get tomorrow's date in YYYY-MM-DD format
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);

const yyyy = tomorrow.getFullYear();
const mm = String(tomorrow.getMonth() + 1).padStart(2, '0');
const dd = String(tomorrow.getDate()).padStart(2, '0');

const tomorrowStr = `${yyyy}-${mm}-${dd}`; // NEW FORMAT

// Filter items whose Visit Start Date matches tomorrow
const shiftsForTomorrow = allItems.filter(
  item => item.json['Visit Start Date'] === tomorrowStr
);

return shiftsForTomorrow;

const allShifts = $input.all();
const grouped = {};

allShifts.forEach(item => {
  const id = item.json['Employee UID'];

  if (!grouped[id]) {
    grouped[id] = {
      name: item.json['Employee Full Name'],
      id,
      phone: item.json['Employee Phone (Mobile)'], // ✅ Add caregiver phone number
      shifts: [],
    };
  }

  grouped[id].shifts.push({
    client: item.json['Client Full Name'],
    start: item.json['Visit Start Time of Day'],
    end: item.json['Visit End Time of Day'],
  });
});

// Convert grouped object → n8n output array
const output = Object.values(grouped).map(entry => ({
  json: {
    name: entry.name,
    id: entry.id,
    phone: entry.phone, // ✅ Include phone in final output
    shifts: entry.shifts,
    shiftCount: entry.shifts.length,
  }
}));

return output;

// Incoming fields from previous node
const name = $json.name;
const shiftCount = $json.shiftCount;
const shifts = $json.shifts;

// Use tomorrow's date for reference
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);

// Helper to pad times (if needed)
const padTime = t => {
  if (!t) return '';
  const [h, m] = t.split(':');
  return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
};

// Collect client names and start times
const details = shifts.map(s => `${s.client} at ${padTime(s.start)}`);

// Build message
let msg = `VISIT REMINDER: You have ${shiftCount} RAH Winnipeg visit${shiftCount > 1 ? 's' : ''} tomorrow with `;

if (shiftCount === 1) {
  msg += `${details[0]}. Check details in Alayacare App.`;
} else if (shiftCount === 2) {
  msg += `${details[0]}, and ${details[1]}. Check details in Alayacare App.`;
} else {
  const lastDetail = details.pop();
  msg += `${details.join(', ')}, and ${lastDetail}. Check details in Alayacare App.`;
}

// Add "do not reply" on a new line
msg += `Kindly DO NOT reply to this number. For any queries, kindly call RAH After Hours @ (431) 887-2273.`;

$json.message = msg;
return $json;

// Get the phone number from either field
let phoneNumber = $json['phone'];

if (!phoneNumber) {
  throw new Error('No phone number found');
}

// Convert to string in case it's a number
phoneNumber = String(phoneNumber).trim();

// STEP 1 — Remove ALL non-digit characters (fixes dashes, spaces, parentheses, etc.)
phoneNumber = phoneNumber.replace(/\D/g, '');

// STEP 2 — Validate phone number length AFTER cleaning
if (phoneNumber.length < 10) {
  throw new Error(`Invalid phone number: ${phoneNumber} (too short)`);
}

// STEP 3 — Add country code if missing (assuming +1)
if (phoneNumber.length === 10) {
  phoneNumber = '1' + phoneNumber;
}

// STEP 4 — Add "+" prefix
if (!phoneNumber.startsWith('+')) {
  phoneNumber = '+' + phoneNumber;
}

// STEP 5 — Final validation
if (!/^\+1\d{10}$/.test(phoneNumber)) {
  console.warn(`Phone number may not be properly formatted: ${phoneNumber}`);
}

// Add formatted phone number to the data
$json.formattedPhoneNumber = phoneNumber;
$json.originalPhoneNumber = $json['Employee Phone (Mobile)'];

// Ensure formatted field is a string
$json.formattedPhoneNumber = String($json.formattedPhoneNumber).trim();

return $json;

// Function node to initialize counters
return [
  {
    json: {
      counts: {
        total: 0,
        success: 0,
        error: 0
      }
    }
  }
];

