if (status === 'failed') counts.error += 1;

// Return updated counts
return [
  {
    json: {
      counts,
      status  // optional: keep the last status if needed
    }
  }
];

let total = 0;
let success = 0;
let error = 0;

for (const item of items) {
  const counts = item.json.counts || {};
  total += counts.total || 0;
  success += counts.success || 0;
  error += counts.error || 0;
}

return [
